SELECT p.*, ste.site_nm AS site_nm, cd_dt.code_label AS panel_type_cd_nm, cd_ds.code_label AS disp_panel_status_cd_nm FROM dp_panel p LEFT JOIN sy_site ste ON ste.site_id = p.site_id LEFT JOIN sy_code cd_dt ON cd_dt.code_grp = 'DISP_TYPE' AND cd_dt.code_value = p.panel_type_cd LEFT JOIN sy_code cd_ds ON cd_ds.code_grp = 'DISP_STATUS' AND cd_ds.code_value = p.disp_panel_status_cd
ORDER BY p.panel_id ASC ORDER BY p.panel_id DESC ORDER BY p.panel_nm ASC ORDER BY p.panel_nm DESC ORDER BY p.reg_date ASC ORDER BY p.reg_date DESC ORDER BY p.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

SELECT p.*, ste.site_nm AS site_nm, cd_dt.code_label AS panel_type_cd_nm, cd_ds.code_label AS disp_panel_status_cd_nm FROM dp_panel p LEFT JOIN sy_site ste ON ste.site_id = p.site_id LEFT JOIN sy_code cd_dt ON cd_dt.code_grp = 'DISP_TYPE' AND cd_dt.code_value = p.panel_type_cd LEFT JOIN sy_code cd_ds ON cd_ds.code_grp = 'DISP_STATUS' AND cd_ds.code_value = p.disp_panel_status_cd
ORDER BY p.panel_id ASC ORDER BY p.panel_id DESC ORDER BY p.panel_nm ASC ORDER BY p.panel_nm DESC ORDER BY p.reg_date ASC ORDER BY p.reg_date DESC ORDER BY p.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

